import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it("should return empty grid when given empty grid", () => {
    expect(nextGeneration([])).toEqual([]);
  });
  it("should kill single isolated cell (underpopulation)", () => {
    expect(nextGeneration([[0, 0]])).toEqual([]);
  });
  it("should kill two isolated cells (both underpopulated)", () => {
    expect(nextGeneration([[0, 0], [2, 2]])).toEqual([]);
  });
  it("should keep alive a cell with exactly 2 neighbors", () => {
    // Horizontal line: (0,0), (1,0), (2,0)
    // Center cell (1,0) has exactly 2 neighbors and survives
    expect(nextGeneration([[0, 0], [1, 0], [2, 0]])).toEqual([[1, 0]]);
  });
  it("should keep alive a cell with exactly 3 neighbors", () => {
    // Pattern: (0,0), (1,0), (2,0), (1,1)
    // Cell (0,0) has neighbors at (1,0), (1,1) = 2 neighbors, survives
    // Cell (1,0) has neighbors at (0,0), (2,0), (1,1) = 3 neighbors, survives
    // Cell (2,0) has neighbors at (1,0), (1,1) = 2 neighbors, survives
    // Cell (1,1) has neighbors at (0,0), (1,0), (2,0) = 3 neighbors, survives
    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]])).toEqual([[0, 0], [1, 0], [2, 0], [1, 1]]);
  });
  it("should kill cell with 4 neighbors (overpopulation)", () => {
    // Plus pattern: (1,0), (0,1), (1,1), (2,1), (1,2)
    // Center cell (1,1) has 4 neighbors: (1,0), (0,1), (2,1), (1,2) → dies (overpopulation)
